// Find prices on Best Buy
const prices = [];
const priceElements = document.querySelectorAll('[data-testid="pricing-price"], .price, .sr-only:contains("$")');
priceElements.forEach(el => {
  const text = el.textContent || el.innerText;
  const match = text.match(/\$\d+\.?\d*/g);
  if (match) {
    match.forEach(price => prices.push(parseFloat(price.replace('$', ''))));
  }
});
// Also try to find product cards
const products = [];
document.querySelectorAll('.product-line, .sku-item, [data-component-type="s-search-result"]').forEach(card => {
  const title = card.querySelector('h3, h4, .title, [data-testid="product-title"]');
  const price = card.querySelector('[data-testid="pricing-price"], .price, .sr-only');
  if (title && price) {
    products.push({
      title: title.textContent.trim(),
      price: price.textContent.trim()
    });
  }
});
JSON.stringify({ prices: [...new Set(prices)].sort((a,b) => a-b), products: products.slice(0, 5) }, null, 2);

