// Get visible prices after scrolling
const prices = [];
const products = [];

// Try multiple selector patterns
const selectors = [
  '[data-testid="price"]',
  '.price', 
  '[aria-label*="price"]',
  'span[class*="price"]',
  'div[class*="price"]',
  '.w-price',
  '[itemprop="price"]'
];

selectors.forEach(selector => {
  document.querySelectorAll(selector).forEach(el => {
    const text = (el.textContent || el.innerText || '').trim();
    const match = text.match(/\$\s?\d+\.?\d*/g);
    if (match) {
      match.forEach(p => {
        const num = parseFloat(p.replace(/[\$\s,]/g, ''));
        if (num > 50 && num < 500) { // Filter for reasonable AirPods prices
          prices.push(num);
        }
      });
    }
  });
});

// Get product titles with prices
document.querySelectorAll('[data-testid="list-item"], [data-testid="product-card"], [role="listitem"]').forEach(item => {
  const titleEl = item.querySelector('[data-testid="item-title"], h3, h4, [role="heading"]');
  const priceEl = item.querySelector('[data-testid="price"], [aria-label*="price"], .price');

  if (titleEl && priceEl) {
    const title = titleEl.textContent.trim().substring(0, 70);
    const priceText = priceEl.textContent.trim();
    const priceMatch = priceText.match(/\$\s?\d+\.?\d*/);
    if (priceMatch) {
      products.push({
        title: title,
        price: priceMatch[0]
      });
    }
  }
});

JSON.stringify({
  uniquePrices: [...new Set(prices)].sort((a,b) => a-b),
  products: products.slice(0, 5)
}, null, 2);

// After scroll, try to find prices again
const prices = [];
const productInfo = [];

// Wait for React to render and search for prices
setTimeout(() => {
  document.querySelectorAll('[data-testid="list-item"], [role="listitem"], .product-item').forEach((item, idx) => {
    if (idx > 10) return; // Limit to first 10 items

    try {
      const title = item.querySelector('[data-testid="item-title"], h3, h4')?.textContent?.trim();
      const priceEl = item.querySelector('[data-testid="price"], [itemprop="price"], [aria-label*="price"]');

      if (priceEl) {
        const priceText = priceEl.textContent || priceEl.getAttribute('content') || priceEl.getAttribute('aria-label');
        if (priceText) {
          const match = String(priceText).match(/\$?\s?(\d+\.?\d*)/);
          if (match) {
            const price = parseFloat(match[1]);
            if (price > 50 && price < 500) {
              prices.push(price);
              productInfo.push({
                title: title?.substring(0, 60) || 'Product ' + (idx + 1),
                price: '$' + price.toFixed(2)
              });
            }
          }
        }
      }
    } catch (e) {}
  });
}, 500);

